#   powershell -ExecutionPolicy Bypass -File .\apply-pricing-fix.ps1
$ErrorActionPreference = "Stop"

function Write-FileB64($Path, $B64) {
  $dir = Split-Path -Parent $Path
  if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  [IO.File]::WriteAllBytes($Path, [Convert]::FromBase64String($B64))
  Write-Host "  wrote $Path"
}

Write-Host "Applying pricing page hardening..."
Write-FileB64 "app\pricing\page.tsx" ""
Write-Host "Done."